codingChallenges.solution:
nums = [45, 12, 78, 34, 56, 89, 23]
largest = max(nums[0], nums[1])
second = min(nums[0], nums[1])
for num in nums[2:]:
    if num > largest:
        second = largest
        largest = num
    elif num > second:
        second = num
print("Second largest:", second)

nums = [1, 2, 3, 2, 4, 3, 5, 1]
result = []
for num in nums:
    if num not in result:
        result.append(num)
print(result)

nums = [3, 1, 2, 3, 4, 2, 3, 1, 5]
counted = []
for num in nums:
    if num not in counted:
        print(f"{num} appears {nums.count(num)} times")
        counted.append(num)
